// Obtener la key de Redis
//const redisKey = $('Split Keys').first().json.keys;
const redisKey = $('Split Keys').item.json.keys;
// Obtener el valor del nodo "Redis - Get Followup Data"
const redisData = $('Redis - Get Followup Data').item.json;
const redisValue = redisData.propertyName;

// Parse the Redis value
let data;
try {
  data = JSON.parse(redisValue);
} catch (e) {
  return { json: { skip: true, reason: 'Invalid JSON' } };
}

// Extract wa_id from key (followup:549876543210)
const wa_id = redisKey.replace('followup:', '');

// Calculate hours since last message
const now = new Date();
const lastMessageTime = new Date(data.timestamp);
const hoursElapsed = (now - lastMessageTime) / (1000 * 60 * 60);

// Determine threshold based on stage
const etapa = data.etapa || 'Abierta';
let threshold;
if (etapa !== 'Cierre') {
  threshold = 0.25; // 15 minutos
}
//else if (etapa === 'Desarrollada') {
//  threshold = 48; // 48 hours
//} 
else {
  threshold = 999; // Don't send for other stages
}

return {
  json: {
    wa_id: wa_id,
    redis_key: redisKey,
    etapa: etapa,
    nombre: data.nombre || '',
    last_bot_msg: data.last_bot_msg || '',
    last_user_msg: data.last_user_msg || '',
    timestamp: data.timestamp,
    hours_elapsed: Math.round(hoursElapsed * 10) / 10,
    threshold_hours: threshold,
    should_check: hoursElapsed >= threshold && etapa !== 'Cierre'
  }
};

// Get memory from previous node - todos los registros de memoria
const allMemory = $input.all();

// Get ALL followup users from previous filter
const followupUsers = $('Filter by Time & Stage').all();

// Process each user separately
const results = followupUsers.map(userItem => {
  const followupData = userItem.json;
  const wa_id = followupData.wa_id;

  // Filter memory for this specific user
  const userMemory = allMemory.filter(msg => msg.json.remitente === wa_id);

  // Format last 5 messages for context
  let memoryText = '';
  if (userMemory.length > 0) {
    const last5 = userMemory.slice(0, 5);
    memoryText = last5.map(msg => 
      `${msg.json.remitente === wa_id ? 'Usuario' : 'Bot'}: ${msg.json.mensaje}`
    ).join('\n');
  }

  return {
    json: {
      ...followupData,
      memory_context: memoryText,
      memory_count: userMemory.length
    }
  };
});

return results;

// Get ALL users from previous node
const allUsers = $input.all();

// Process each user separately
const results = allUsers.map(item => {
  const data = item.json;

  const prompt = `Analiza esta conversación y determina si es apropiado enviar un mensaje de followup proactivo.

Contexto:
- Tiempo sin respuesta: ${data.hours_elapsed} horas
- Etapa de venta: ${data.etapa}
- Último mensaje del usuario: "${data.last_user_msg}"
- Último mensaje del bot: "${data.last_bot_msg}"
- Historial reciente:
${data.memory_context}

Responde SOLO con un JSON válido en este formato exacto:
{
  "enviar_followup": true,
  "razon": "explicación breve"
}

NO enviar followup si:
- Usuario dijo que se contactará después ("mañana", "después", "más tarde")
- Usuario pidió que le envíen información por email u otro medio
- Usuario se despidió claramente
- Conversación llegó a un cierre natural
- Usuario mostró desinterés explícito ("no me interesa", "gracias pero no")
- Usuario pidió específicamente no ser contactado
- La última interacción fue el bot enviando información completa

SÍ enviar followup si:
- Usuario hizo una consulta y nunca respondió
- Usuario mostró interés pero la conversación se cortó abruptamente
- Conversación quedó inconclusa en medio de una negociación
- Usuario estaba evaluando modelos y no volvió

Responde SOLO el JSON, sin texto adicional.`;

  return {
    json: {
      ...data,
      validation_prompt: prompt
    }
  };
});

return results;

