// Process ALL items - one GPT response per user
const allInputs = $input.all();

// Map each GPT response to its corresponding user data
const results = allInputs.map((inputItem, index) => {
  const gptResponse = inputItem.json;

  // Get the corresponding item from Prepare Validation Prompt
  const previousData = $('Prepare Validation Prompt').all()[index].json;

  let decision;
  try {
    const content = gptResponse.choices[0].message.content.trim();
    // Try to extract JSON if wrapped in markdown
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    const jsonString = jsonMatch ? jsonMatch[0] : content;
    decision = JSON.parse(jsonString);
  } catch (e) {
    // Default to not sending if parsing fails
    decision = {
      enviar_followup: false,
      razon: 'Error parsing GPT response'
    };
  }

  return {
    json: {
      ...previousData,
      should_send: decision.enviar_followup === true,
      gpt_reason: decision.razon
    }
  };
});

return results;

